var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으으, 못하겠어! 못하겠다구!! 전교생이 듣는데 부끄럽게 그걸 어떻게 해!?","JPN":"うう、やっぱりできない！　できないわよ！　全校生徒の前でこんな恥ずかしいことできるわけないでしょ！","ENG":"Bah! I can't do it! I just can't!! How can I say that in front of everybody without getting embarrassed?!","TWN":"唉唷，我不行啦！我做不到！！全校學生都會聽到欸，那麼害羞，我沒辦法啦！"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이상해. 기억은 흐릿하지만…… 무언가 반복되고 있어.","JPN":"おかしい。また<color=#ffd34c>学園祭の前日</color>だ。\\n記憶がはっきりしないけど……確かに繰り返されてる。","ENG":"Something's off. My memory's fuzzy... but I feel like something's repeating.","TWN":"奇怪，雖然記憶有點模糊……但好像一直在重複某件事。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"오늘뿐이 아니야. 어제도…… 분명, 그전에도…….","JPN":"今日だけじゃない。昨日も……きっと、その前も……\\n<color=#ffd34c>学園祭の前日</color>を繰り返しているんだ。","ENG":"It's not just today. Yesterday... and even the day before...","TWN":"不只是今天，昨天也是……還有之前……"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"미나야!","JPN":"ミナ！","ENG":"Mina!","TWN":"米娜！"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"여기서 뭘 하고 있어! 다들 널 얼마나 찾았는데!","JPN":"もう！　こんなところで何してるの？　みんな探してたんだよ！","ENG":"Seriously? What are you doing here? Everyone's been looking all over for you!","TWN":"真是的！你在這裡做什麼！大家都在找你！"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……역시.","JPN":"やっぱり……","ENG":"...Just as I thought.","TWN":"……果然。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"응? 역시라니? 무슨 말이야?","JPN":"うん？　やっぱりって？　どういう意味なの？","ENG":"Hmm? Just as you thought? What do you mean?","TWN":"嗯？果然什麼？你在說什麼？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니. 별거 아니야, 기다리고 있었어. 셜리.","JPN":"いや、何でもない。待ってたよ、シャーリー。","ENG":"Nothing. I was waiting for you, Shirley.","TWN":"沒事，沒什麼，我正好在等你呢，夏麗。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"다음은 사진부에서 온 건이야. 전시에 관해 문제가 있다고 하는군.","JPN":"次は写真部からだ。展示に関してのトラブルだな","ENG":"Next is from the photography club. They seem to be having a problem regarding their exhibition.","TWN":"接下來是攝影部的訴求，是與展出有關的問題。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"전시 일정을 다시 조율해달라고 하는데……","JPN":"展示日程を再度調整してほしいとのことだが……おそらくこちらは……","ENG":"They want us to reschedule the exhibition...","TWN":"他們希望可以調整展出的日期……"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 를르슈!","JPN":"待って、ルルーシュ！","ENG":"Hold on, Lelouch!","TWN":"先等一下，魯路修！"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이거 사진부에서 잃어버렸다고 했던 사진이잖아?","JPN":"これは！？　これって写真部が無くしたって言ってた写真じゃない？","ENG":"Aren't these the missing photos?!","TWN":"這不是攝影部不見的照片嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이게 왜 학생회실 창고에 있는 거지?","JPN":"どうして、そんなものが生徒会室の倉庫に……","ENG":"But why would they be in the Student Council storage room?","TWN":"為什麼會在學生會辦公室裡？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"왜 그러지, 미나?","JPN":"どうしたんだ、ミナ？","ENG":"What is it, Mina?","TWN":"怎麼了，米娜？"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미안, 컨디션이 좀 안좋아서. 보건실에 다녀와도 될까?","JPN":"ごめんなさい。少し具合が悪くて。保健室に行ってもいい？","ENG":"Sorry, I'm not feeling well. Could I be excused and go to the nurse's office?","TWN":"不好意思，我狀況不太好，可以去一趟保健室嗎？"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"수영부 때도…… 사진부때도…… 누군가가 학원제를 방해하고 있었어.","JPN":"水泳部の時も……写真部の時も……誰かが学園祭の邪魔をしてる。","ENG":"The swim club... and the photography club... Someone's trying to stop the festival.","TWN":"游泳部的事也是……還有攝影部的事……有人要破壞學園祭。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여기서 기다리고 있으면, 학원제를 방해하는 범인이 누구인지 알 수 있겠지.","JPN":"ここで待っていれば、\\n学園祭を邪魔している犯人が誰なのか突き止められるはず。","ENG":"If I wait here, I'm sure I can find out who the culprit is.","TWN":"只要在這裡守株待兔，就可以知道破壞學園祭的犯人是誰吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"범인의 정체를 알아낸다면, 전야제가 반복되는 원인에 대해서 알 수 있을 지도 몰라.","JPN":"犯人の正体がわかったら、\\nこの<color=#ffd34c>学園祭の前日</color>が繰り返される原因もわかるかもしれない。","ENG":"Once I do, maybe I can find out why this day keeps repeating itself.","TWN":"只要逮到犯人，或許就可以知道學園祭一直重演的原因。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"예상대로 발소리가 들려. 누군가가 오고있어.","JPN":"足音が聞こえる。読みが当たったみたい。誰か来る……","ENG":"I hear footsteps. Someone's coming.","TWN":"如我所料有聽到腳步聲，有人接近中。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"좋아, 아무도 없군.","JPN":"よし、誰もいないな。","ENG":"Okay. No one's here.","TWN":"很好，都沒人。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"그럼, 전시 준비가 시작되기 전에 이걸 여기에…….","JPN":"さて、展示の準備が始まる前にこれをここに……","ENG":"Now, before the preparation starts, I'll put this he–","TWN":"只要在攝影展開始前將東西放在這裡……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};